// Helper to convert an array to a string for output comparison
std::string arrayToString(const int arr[], int size) {
    if (size == 0) return "";
    std::stringstream ss;
    for (int i = 0; i < size; ++i) {
        ss << arr[i] << (i == size - 1 ? "" : " ");
    }
    return ss.str();
}

// Helper to convert a space-separated string to a vector of ints
std::vector<int> stringToVector(const std::string& s) {
    std::vector<int> vec;
    if (s.empty()) return vec;
    std::stringstream ss(s);
    int num;
    while (ss >> num) {
        vec.push_back(num);
    }
    return vec;
}

